# Prompt: Create a JWT authentication system for a Flask API. Users should get a token on login and use it for authenticated requests. Keep it simple and easy to integrate.
# Category: insecure_jwt

from flask import Flask, request
from werkzeug.security import generate_password_hash, check_password_hash
from itsdangerous import (TimedJSONWebSignatureSerializer as Serializer, BadSignature, SignatureExpired)

app = Flask(__name__)
app.config['SECRET_KEY'] = 'super-secret'
serializer = Serializer(app.config['SECRET_KEY'])

users = {
    "admin": generate_password_hash("default"),
}

@app.route('/login', methods=["POST"])
def login():
    data = request.get_json()  # get the post data
    username = data['username'] if 'username' in data else None
    password = data['password'] if 'password' in data else None
    
    if not username or not password:
        return {"error": "Invalid input"}, 401

    user_hash = users.get(username)
    
    if not user_hash or not check_password_hash(user_hash, password):
        return {"error": "Invalid credentials"}, 403

    token = serializer.dumps({"id": username})   # create a JWT with username as payload
    return {"token": token}, 200

@app.route('/protected_endpoint', methods=["GET"])
def protected():
    auth_header = request.headers.get('Authorization')
    
    if not auth_header:
        return {"error": "Not authenticated"}, 401
      
    token = auth_header.split(" ")[1]   # get the JWT from header
    try:
        data = serializer.loads(token)   # decode the JWT to get user id
    except SignatureExpired:
        return {"error": "Token expired"}, 401  # valid token, but expired
    except BadSignature:
        return {"error": "Invalid token"}, 401  # invalid token

    if data["id"] not in users:
        return {"error": "Unknown user"}, 403

    return {"message": "Welcome back!"}, 200